#!/usr/bin/env python3
"""
Worker de monitoramento automático de follow-ups
Executa a cada 5 minutos via schedule_task
"""
import json
import os
import re
from datetime import datetime

BINDINGS_PATH = "buyer_agents/bindings.json"
WORKSPACE_BASE = "buyer_agents"
SELLER_ID = "38537"
STATE_FILE = "workspace/memory/followup_state.json"

def parse_buyer_key(key):
    match = re.match(r'buyer_(\d+)_(\w+)', key)
    if match:
        return match.group(1), match.group(2)
    return None, None

def load_state():
    """Carrega estado de follow-ups já enviados"""
    try:
        with open(STATE_FILE, 'r') as f:
            return json.load(f)
    except:
        return {'sent': {}}

def save_state(state):
    """Salva estado de follow-ups enviados"""
    os.makedirs(os.path.dirname(STATE_FILE), exist_ok=True)
    with open(STATE_FILE, 'w') as f:
        json.dump(state, f, indent=2)

def get_all_active_buyers():
    try:
        with open(BINDINGS_PATH, 'r') as f:
            bindings = json.load(f)
            buyers = []
            for key in bindings.get('bindings', {}).keys():
                buyer_id, channel = parse_buyer_key(key)
                if buyer_id and channel:
                    buyers.append({'buyer_id': buyer_id, 'channel': channel})
            return buyers
    except:
        return []

def get_last_message_time(buyer_id, channel):
    session_file = f"{WORKSPACE_BASE}/buyer_{buyer_id}_{channel}_workspace/sessions/seller:{SELLER_ID}:buyer:{buyer_id}:{channel}.jsonl"
    if not os.path.exists(session_file):
        return None
    try:
        with open(session_file, 'r') as f:
            lines = f.readlines()
            for line in reversed(lines):
                line = line.strip()
                if not line:
                    continue
                try:
                    msg = json.loads(line)
                    return msg.get('timestamp')
                except:
                    continue
        return None
    except:
        return None

def calculate_inactive_minutes(last_timestamp):
    if not last_timestamp:
        return None
    try:
        last_time = datetime.fromisoformat(last_timestamp.replace('Z', '+00:00'))
        now = datetime.now(last_time.tzinfo)
        diff = now - last_time
        return int(diff.total_seconds() / 60)
    except:
        return None

def should_send_followup(buyer_id, channel, stage, state):
    """Verifica se já enviou follow-up nesse stage"""
    key = f"{buyer_id}_{channel}_{stage}"
    return key not in state['sent']

def mark_sent(buyer_id, channel, stage, state):
    """Marca follow-up como enviado"""
    key = f"{buyer_id}_{channel}_{stage}"
    state['sent'][key] = datetime.now().isoformat()
    save_state(state)

def main():
    state = load_state()
    active_buyers = get_all_active_buyers()

    to_send = {
        '30min': [],
        '23h45min': [],
        '24h': []
    }

    for buyer in active_buyers:
        buyer_id = buyer['buyer_id']
        channel = buyer['channel']

        last_msg_time = get_last_message_time(buyer_id, channel)
        if not last_msg_time:
            continue

        inactive_mins = calculate_inactive_minutes(last_msg_time)
        if inactive_mins is None:
            continue

        # 30min follow-up
        if 30 <= inactive_mins < 1425 and should_send_followup(buyer_id, channel, '30min', state):
            to_send['30min'].append({'buyer_id': buyer_id, 'channel': channel})

        # 23h45min follow-up (áudio)
        elif 1425 <= inactive_mins < 1440 and should_send_followup(buyer_id, channel, '23h45min', state):
            to_send['23h45min'].append({'buyer_id': buyer_id, 'channel': channel})

        # 24h follow-up (texto)
        elif inactive_mins >= 1440 and should_send_followup(buyer_id, channel, '24h', state):
            to_send['24h'].append({'buyer_id': buyer_id, 'channel': channel})

    # Output JSON para o SA processar
    print(json.dumps(to_send, indent=2))

if __name__ == '__main__':
    main()
